    10→function FormField({ field, value, onChange }) {
    11→  const commonProps = {
    12→    id: field.id,
    13→    value: value || '',
    14→    onChange: (e) => onChange(field.id, e.target.value),
    15→    placeholder: field.placeholder || '',
    16→    required: field.required,
    17→  };
    18→
    19→  if (field.type === 'textarea') {
    20→    return (
    21→      <div className="form-group">
    22→        <label className="form-label" htmlFor={field.id}>
    23→          {field.label}
    24→          {field.required && <span className="required-mark"> *</span>}
    25→        </label>
    26→        <textarea className="form-textarea" rows={4} {...commonProps} />
    27→      </div>
    28→    );
    29→  }
    30→
    31→  if (field.type === 'select') {
    32→    return (
    33→      <div className="form-group">
    34→        <label className="form-label" htmlFor={field.id}>
    35→          {field.label}
    36→          {field.required && <span className="required-mark"> *</span>}
    37→        </label>
    38→        <select className="form-select" {...commonProps}>
    39→          <option value="">Select an option...</option>
    40→          {field.options.map((opt) => (
    41→            <option key={opt} value={opt}>{opt}</option>
    42→          ))}
    43→        </select>
    44→      </div>
    45→    );
    46→  }
    47→
    48→  return (
    49→    <div className="form-group">
    50→      <label className="form-label" htmlFor={field.id}>
    51→        {field.label}
    52→        {field.required && <span className="required-mark"> *</span>}
    53→      </label>
    54→      <input type="text" className="form-input" {...commonProps} />
    55→    </div>
    56→  );
    57→}
