    59→export default function AIToolInterface({ tool, categoryId }) {
    60→  const [inputs, setInputs] = useState({});
    61→  const [output, setOutput] = useState('');
    62→  const [isStreaming, setIsStreaming] = useState(false);
    63→  const [error, setError] = useState('');
    64→  const [copied, setCopied] = useState(false);
    65→  const [wordCount, setWordCount] = useState(0);
    66→  const outputRef = useRef(null);
    67→  const abortRef = useRef(false);
    68→
    69→  const { currentUser } = useAuth();
    70→  const { canUseTool, trackUsage, isAtLimit, subscription } = useSubscription();
    71→
    72→  // Reset when tool changes
    73→  useEffect(() => {
    74→    setInputs({});
    75→    setOutput('');
    76→    setError('');
    77→    setIsStreaming(false);
    78→  }, [tool?.id]);
    79→
    80→  // Track word count
    81→  useEffect(() => {
    82→    if (output) {
    83→      setWordCount(output.split(/\s+/).filter(Boolean).length);
    84→    } else {
    85→      setWordCount(0);
    86→    }
    87→  }, [output]);
    88→
    89→  // Auto-scroll output
    90→  useEffect(() => {
    91→    if (outputRef.current && isStreaming) {
    92→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    93→    }
    94→  }, [output, isStreaming]);
    95→
    96→  function handleInputChange(fieldId, value) {
    97→    setInputs((prev) => ({ ...prev, [fieldId]: value }));
    98→  }
    99→
   100→  function validateInputs() {
   101→    const required = tool.inputs.filter((f) => f.required);
   102→    for (const field of required) {
   103→      if (!inputs[field.id] || inputs[field.id].trim() === '') {
   104→        return `"${field.label}" is required`;
   105→      }
   106→    }
   107→    return null;
   108→  }
   109→
   110→  async function handleGenerate(e) {
   111→    e.preventDefault();
   112→    setError('');
   113→
   114→    if (!currentUser) {
   115→      setError('Please sign in to use this tool.');
   116→      return;
   117→    }
   118→
   119→    if (!canUseTool(categoryId)) {
   120→      if (isAtLimit()) {
   121→        setError('Daily usage limit reached. Upgrade to Pro for unlimited access.');
   122→      } else {
   123→        setError('This category requires a Pro plan.');
   124→      }
   125→      return;
   126→    }
   127→
   128→    const validationError = validateInputs();
   129→    if (validationError) {
   130→      setError(validationError);
   131→      return;
   132→    }
   133→
   134→    setOutput('');
   135→    setIsStreaming(true);
   136→    abortRef.current = false;
   137→
   138→    await streamAIResponse({
   139→      categoryId,
   140→      toolId: tool.id,
   141→      inputs,
   142→      onChunk: (text) => {
   143→        if (!abortRef.current) {
   144→          setOutput((prev) => prev + text);
   145→        }
   146→      },
   147→      onDone: () => {
   148→        setIsStreaming(false);
   149→        trackUsage();
   150→      },
   151→      onError: (msg) => {
   152→        setIsStreaming(false);
   153→        setError(msg);
   154→      },
   155→    });
   156→  }
   157→
   158→  function handleStop() {
   159→    abortRef.current = true;
   160→    setIsStreaming(false);
   161→  }
   162→
   163→  async function handleCopy() {
   164→    if (!output) return;
   165→    await navigator.clipboard.writeText(output);
   166→    setCopied(true);
   167→    setTimeout(() => setCopied(false), 2000);
   168→  }
   169→
   170→  function handleClear() {
   171→    setOutput('');
   172→    setError('');
   173→    setInputs({});
   174→  }
   175→
   176→  const locked = !canUseTool(categoryId) && !isAtLimit();
   177→  const atLimit = isAtLimit() && subscription === 'free';
   178→
   179→  if (!tool) {
   180→    return (
   181→      <div className="ai-tool__empty">
   182→        <div className="ai-tool__empty-icon">⬅️</div>
   183→        <h3>Select a tool to get started</h3>
   184→        <p>Choose a tool from the sidebar to generate AI-powered content</p>
   185→      </div>
   186→    );
   187→  }
   188→
   189→  return (
   190→    <div className="ai-tool">
   191→      {/* Header */}
   192→      <div className="ai-tool__header">
   193→        <div className="ai-tool__title-row">
   194→          <span className="ai-tool__icon">{tool.icon}</span>
   195→          <div>
   196→            <h2 className="ai-tool__title">{tool.name}</h2>
   197→            <p className="ai-tool__description">{tool.description}</p>
   198→          </div>
   199→        </div>
   200→      </div>
   201→
   202→      {/* Upgrade notice */}
   203→      {(locked || atLimit) && (
   204→        <div className="ai-tool__upgrade">
   205→          <div className="ai-tool__upgrade-icon">🔒</div>
   206→          <div>
   207→            <strong>{atLimit ? 'Daily limit reached' : 'Pro feature'}</strong>
   208→            <p>
   209→              {atLimit
   210→                ? 'You\'ve used all 5 free daily requests. Upgrade to Pro for unlimited access.'
   211→                : 'This category is available on Pro and Business plans.'}
   212→            </p>
   213→          </div>
   214→          <Link to="/pricing" className="btn btn-primary btn-sm">Upgrade Now</Link>
   215→        </div>
   216→      )}
   217→
   218→      <div className="ai-tool__layout">
   219→        {/* Input Panel */}
   220→        <div className="ai-tool__panel ai-tool__input-panel">
   221→          <h3 className="ai-tool__panel-title">📝 Your Inputs</h3>
   222→          <form onSubmit={handleGenerate}>
   223→            {tool.inputs.map((field) => (
   224→              <FormField
   225→                key={field.id}
   226→                field={field}
   227→                value={inputs[field.id]}
   228→                onChange={handleInputChange}
   229→              />
   230→            ))}
   231→
   232→            {error && (
   233→              <div className="alert alert-error" style={{ marginBottom: '1rem' }}>
   234→                ⚠️ {error}
   235→              </div>
   236→            )}
   237→
   238→            <div className="ai-tool__actions">
   239→              {isStreaming ? (
   240→                <button type="button" className="btn btn-danger" onClick={handleStop}>
   241→                  ⏹ Stop Generating
   242→                </button>
   243→              ) : (
   244→                <button
   245→                  type="submit"
   246→                  className="btn btn-primary"
   247→                  disabled={locked || atLimit}
   248→                >
   249→                  <span>✨</span>
   250→                  Generate with AI
   251→                </button>
   252→              )}
   253→              {output && !isStreaming && (
   254→                <button type="button" className="btn btn-ghost btn-sm" onClick={handleClear}>
   255→                  Clear
   256→                </button>
   257→              )}
   258→            </div>
   259→          </form>
   260→        </div>
   261→
   262→        {/* Output Panel */}
   263→        <div className="ai-tool__panel ai-tool__output-panel">
   264→          <div className="ai-tool__output-header">
   265→            <h3 className="ai-tool__panel-title">
   266→              {isStreaming ? (
   267→                <span className="ai-tool__streaming">
   268→                  <span className="ai-tool__streaming-dot" />
   269→                  AI is generating...
   270→                </span>
   271→              ) : output ? (
   272→                '✅ AI Output'
   273→              ) : (
   274→                '🤖 AI Output'
   275→              )}
   276→            </h3>
   277→            {output && (
   278→              <div className="ai-tool__output-controls">
   279→                <span className="ai-tool__word-count">{wordCount} words</span>
   280→                <button
   281→                  className="btn btn-secondary btn-sm"
   282→                  onClick={handleCopy}
   283→                  disabled={isStreaming}
   284→                >
   285→                  {copied ? '✅ Copied!' : '📋 Copy'}
   286→                </button>
   287→              </div>
   288→            )}
   289→          </div>
   290→
   291→          <div className="ai-tool__output-body" ref={outputRef}>
   292→            {!output && !isStreaming && (
   293→              <div className="ai-tool__output-placeholder">
   294→                <div className="ai-tool__placeholder-icon">✨</div>
   295→                <p>Fill in the inputs on the left and click <strong>Generate with AI</strong> to create content.</p>
   296→                <div className="ai-tool__placeholder-features">
   297→                  <span>📊 Structured output</span>
   298→                  <span>🎯 Category-specific</span>
   299→                  <span>⚡ Real-time streaming</span>
   300→                </div>
   301→              </div>
   302→            )}
   303→
   304→            <AnimatePresence>
   305→              {(output || isStreaming) && (
   306→                <motion.div
   307→                  className="ai-tool__output-content markdown-output"
   308→                  initial={{ opacity: 0 }}
   309→                  animate={{ opacity: 1 }}
   310→                  transition={{ duration: 0.3 }}
   311→                >
   312→                  <ReactMarkdown>{output}</ReactMarkdown>
   313→                  {isStreaming && <span className="ai-tool__cursor">▋</span>}
   314→                </motion.div>
   315→              )}
   316→            </AnimatePresence>
   317→          </div>
   318→        </div>
   319→      </div>
   320→    </div>
   321→  );
   322→}
